using System.Security.Cryptography.X509Certificates;
using Azure.Identity;
using Azure.Security.KeyVault.Secrets;

// Load from Windows/macOS certificate store
using var store = new X509Store(StoreName.My, StoreLocation.CurrentUser);
store.Open(OpenFlags.ReadOnly);
var cert = store.Certificates
    .Find(X509FindType.FindByThumbprint, "<thumbprint>", validOnly: false)
    .OfType<X509Certificate2>()
    .First();

var credential = new ClientCertificateCredential(
    tenantId:    Environment.GetEnvironmentVariable("AZURE_TENANT_ID"),
    clientId:    Environment.GetEnvironmentVariable("AZURE_CLIENT_ID"),
    certificate: cert
);

var client = new SecretClient(new Uri("https://my-vault.vault.azure.net"), credential);
var secret = await client.GetSecretAsync("my-secret");
Console.WriteLine(secret.Value.Value);

using Azure.Identity;
using Azure.Security.KeyVault.Certificates;
using System.Security.Cryptography.X509Certificates;

// Step 1: use managed identity to download certificate from Key Vault
var miCredential = new DefaultAzureCredential();
var certClient = new CertificateClient(
    new Uri("https://my-vault.vault.azure.net"),
    miCredential
);

// Download as PFX bytes
var certPolicy = await certClient.GetCertificateAsync("MyServicePrincipalCert");
byte[] pfxBytes = certPolicy.Value.Cer;   // DER-encoded
var x509 = new X509Certificate2(pfxBytes);

// Step 2: use the certificate credential for the third-party tenant
var spCredential = new ClientCertificateCredential(
    tenantId:    "<third-party-tenant>",
    clientId:    "<client-id>",
    certificate: x509
);

# Create a self-signed certificate with auto-renewal in Key Vault
az keyvault certificate create \
    --vault-name MyVault \
    --name MyServicePrincipalCert \
    --policy '{
        "keyProperties": {"keyType": "RSA", "keySize": 4096, "exportable": true},
        "secretProperties": {"contentType": "application/x-pkcs12"},
        "x509CertificateProperties": {
            "subject": "CN=my-service-principal",
            "validityInMonths": 12
        },
        "lifetimeActions": [{
            "trigger": {"daysBeforeExpiry": 30},
            "action": {"actionType": "AutoRenew"}
        }],
        "issuerParameters": {"name": "Self"}
    }'

# After renewal, update the App Registration with the new public cert
# (automate this with an Event Grid → Function App → az ad app credential reset pipeline)

# Report all certificate credentials expiring within 60 days
Connect-MgGraph -Scopes 'Application.Read.All'

$cutoff = (Get-Date).AddDays(60)
$report = @()

Get-MgApplication -All | ForEach-Object {
    $app = $_
    $app.KeyCredentials | Where-Object { $_.EndDateTime -lt $cutoff } | ForEach-Object {
        $report += [PSCustomObject]@{
            AppName     = $app.DisplayName
            AppId       = $app.AppId
            CertName    = $_.DisplayName
            Thumbprint  = $_.CustomKeyIdentifier
            ExpiresOn   = $_.EndDateTime
            DaysLeft    = ($_.EndDateTime - (Get-Date)).Days
        }
    }
}

$report | Sort-Object DaysLeft | Format-Table -AutoSize

# Export to CSV for tracking
$report | Export-Csv -Path cert-expiry-report.csv -NoTypeInformation
